@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    Your privacy is important to us. This page outlines how we collect, use, and
    protect your personal information when you use our application.
</p>

<h2>Cookie Consent Status</h2>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>Information We Collect</h2>
<p>
    We may collect information that you provide directly, such as when you create an
    account, fill out a form, or communicate with us. We also collect certain
    information automatically, including cookies and usage data.
</p>

<h2>How We Use Cookies</h2>
<p>
    Cookies are small text files stored on your device. We use cookies to improve your
    experience, remember your preferences, and analyse site traffic.
</p>

<h2>Your Rights</h2>
<p>
    You have the right to access, correct, or delete your personal data at any time.
    Contact us if you wish to exercise these rights.
</p>

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

